          "type": "image",
          "src": "https://mmbiz.qpic.cn/sz_mmbiz_png/Aic1RkSKrBs8SqXQGlzaEsj8FHA6ghibZEKSmU960UwzzDEfyrV84H50g6qV2NN0xP88EjYdRseiaee4GDKrvicrog/640?wx_fmt=png&from=appmsg",
          "alt": ""
