          "type": "image",
          "src": "https://mmbiz.qpic.cn/sz_mmbiz_png/Aic1RkSKrBsicIELbedf1Ziat1poTpDF4rXTCiap4SoUicmo5GpaaoXMOUs7kQHoawvEDRODvnNzMPjG8l9SE1WncIg/640?wx_fmt=png&from=appmsg",
          "alt": "Image"
