          "type": "image",
          "src": "https://mmbiz.qpic.cn/mmbiz_png/HibrYDJehdiaeAjwJJ6TgJCicfniaDLXdb0H0XBtpnOfXyNDwlSCMIXCeiaTDZtpe7aX33mryzNnx7iaFcESWNA8LesQ/640?wx_fmt=png",
